  1→import { afterAll, beforeAll, describe, expect, it } from "bun:test";
  2→import { randomUUID } from "node:crypto";
  3→import { readFileSync } from "node:fs";
  4→import { join } from "node:path";
  5→import { RecordId, Surreal } from "surrealdb";
  6→import { createCreateWorkItemTool } from "../../../app/src/server/chat/tools/create-work-item";
  7→import { testAI } from "../acceptance-test-kit";
  8→
  9→const surrealUrl = process.env.SURREAL_URL ?? "ws://127.0.0.1:8000/rpc";
 10→const surrealUsername = process.env.SURREAL_USERNAME ?? "root";
 11→const surrealPassword = process.env.SURREAL_PASSWORD ?? "root";
 12→
 13→let surreal: Surreal;
 14→let namespace: string;
 15→let database: string;
 16→let workspaceRecord: RecordId<"workspace", string>;
 17→let conversationRecord: RecordId<"conversation", string>;
 18→let personRecord: RecordId<"person", string>;
 19→let identityRecord: RecordId<"identity", string>;
 20→let messageRecord: RecordId<"message", string>;
 21→
 22→beforeAll(async () => {
 23→  const runId = `${Date.now()}_${Math.floor(Math.random() * 100000)}`;
 24→  namespace = `smoke_cwi_edge_${runId}`;
 25→  database = `cwi_edge_${Math.floor(Math.random() * 100000)}`;
 26→
 27→  surreal = new Surreal();
 28→  await surreal.connect(surrealUrl);
 29→  await surreal.signin({ username: surrealUsername, password: surrealPassword });
 30→  await surreal.query(`DEFINE NAMESPACE ${namespace};`);
 31→  await surreal.use({ namespace });
 32→  await surreal.query(`DEFINE DATABASE ${database};`);
 33→  await surreal.use({ namespace, database });
 34→
 35→  const schemaSql = readFileSync(join(process.cwd(), "schema", "surreal-schema.surql"), "utf8");
 36→  await surreal.query(schemaSql);
 37→
 38→  const now = new Date();
 39→
 40→  workspaceRecord = new RecordId("workspace", randomUUID());
 41→  await surreal.create(workspaceRecord).content({
 42→    name: "Edge Test Workspace",
 43→    status: "active",
 44→    onboarding_complete: true,
 45→    onboarding_turn_count: 0,
 46→    onboarding_summary_pending: false,
 47→    onboarding_started_at: now,
 48→    created_at: now,
 49→  });
 50→
 51→  conversationRecord = new RecordId("conversation", randomUUID());
 52→  await surreal.create(conversationRecord).content({
 53→    workspace: workspaceRecord,
 54→    createdAt: now,
 55→    updatedAt: now,
 56→  });
 57→
 58→  personRecord = new RecordId("person", randomUUID());
 59→  await surreal.query("CREATE $record CONTENT $content;", {
 60→    record: personRecord,
 61→    content: { name: "Test User", contact_email: "test@test.local", created_at: now, updated_at: now },
 62→  });
 63→  identityRecord = new RecordId("identity", randomUUID());
 64→  await surreal.query("CREATE $record CONTENT $content;", {
 65→    record: identityRecord,
 66→    content: { name: "Test User", type: "human", workspace: workspaceRecord, created_at: now },
 67→  });
 68→  await surreal.query("RELATE $identity->identity_person->$person SET added_at = time::now();", {
 69→    identity: identityRecord,
 70→    person: personRecord,
 71→  });
 72→  await surreal.query("RELATE $identity->member_of->$workspace SET added_at = time::now();", {
 73→    identity: identityRecord,
 74→    workspace: workspaceRecord,
 75→  });
 76→
 77→  messageRecord = new RecordId("message", randomUUID());
 78→  await surreal.query("CREATE $record CONTENT $content;", {
 79→    record: messageRecord,
 80→    content: {
 81→      conversation: conversationRecord,
 82→      role: "user",
 83→      text: "Create a project and features",
 84→      createdAt: now,
 85→    },
 86→  });
 87→}, 30_000);
 88→
 89→afterAll(async () => {
 90→  if (!surreal) return;
 91→  try {
 92→    await surreal.query(`REMOVE DATABASE ${database};`);
 93→    await surreal.query(`REMOVE NAMESPACE ${namespace};`);
 94→  } catch {}
 95→  await surreal.close().catch(() => {});
 96→}, 10_000);
 97→
 98→// ── Helpers ──
 99→
100→function makeTool() {
101→  return createCreateWorkItemTool({
102→    surreal,
103→    embeddingModel: testAI.embeddingModel as any,
104→    embeddingDimension: testAI.embeddingDimension,
105→    extractionModelId: testAI.extractionModelId,
106→    extractionModel: testAI.extractionModel,
107→    extractionStoreThreshold: 0.5,
108→  });
109→}
110→
111→function makeOptions() {
112→  return {
113→    toolCallId: "call-1",
114→    messages: [],
115→    experimental_context: {
116→      actor: "pm_agent" as const,
117→      humanPresent: true,
118→      identityRecord,
119→      workspaceRecord,
120→      conversationRecord,
121→      currentMessageRecord: messageRecord,
122→      latestUserText: "Create a project and features",
123→    },
124→  } as any;
125→}
126→
127→async function countEdges(table: string, from: RecordId, to: RecordId): Promise<number> {
128→  const [rows] = await surreal
129→    .query<[Array<{ count: number }>]>(
130→      `SELECT count() AS count FROM ${table} WHERE \`in\` = $from AND out = $to GROUP ALL;`,
131→      { from, to },
132→    )
133→    .collect<[Array<{ count: number }>]>();
134→  return rows.length > 0 ? rows[0].count : 0;
135→}
136→
137→function parseEntityId(entityId: string): RecordId {
138→  const [table, id] = entityId.split(":");
139→  return new RecordId(table, id);
140→}
141→
142→// ── Tests ──
143→
144→describe("create_work_item has_feature edge regression", () => {
145→  it("creates has_feature edge when project exists before feature creation (sequential)", async () => {
146→    const tool = makeTool();
147→    const options = makeOptions();
148→
149→    // Step 1: create project (simulates first tool call step)
150→    const projectResult = await tool.execute!(
151→      { kind: "project", title: "Orders", rationale: "Order management system" },
152→      options,
153→    );
154→    expect(projectResult.error).toBeUndefined();
155→    expect(projectResult.kind).toBe("project");
156→
157→    // Step 2: create feature scoped to the project (simulates second tool call step)
158→    const featureResult = await tool.execute!(
159→      { kind: "feature", title: "Order Tracking", rationale: "Track order status", project: "Orders" },
160→      options,
161→    );
162→    expect(featureResult.error).toBeUndefined();
163→    expect(featureResult.kind).toBe("feature");
164→
165→    // Verify has_feature edge exists
166→    const projectRecord = parseEntityId(projectResult.entity_id);
167→    const featureRecord = parseEntityId(featureResult.entity_id);
168→    const edgeCount = await countEdges("has_feature", projectRecord, featureRecord);
169→    expect(edgeCount).toBe(1);
170→  });
171→
172→  it("creates belongs_to edge when task references existing project", async () => {
173→    const tool = makeTool();
174→    const options = makeOptions();
175→
176→    // Step 1: create project
177→    const projectResult = await tool.execute!(
178→      { kind: "project", title: "Inventory", rationale: "Inventory management" },
179→      options,
180→    );
181→    expect(projectResult.kind).toBe("project");
182→
183→    // Step 2: create task scoped to the project
184→    const taskResult = await tool.execute!(
185→      { kind: "task", title: "Build stock counter", rationale: "Count inventory items", project: "Inventory" },
186→      options,
187→    );
188→    expect(taskResult.kind).toBe("task");
189→
190→    // Verify belongs_to edge exists
191→    const projectRecord = parseEntityId(projectResult.entity_id);
192→    const taskRecord = parseEntityId(taskResult.entity_id);
193→    const edgeCount = await countEdges("belongs_to", taskRecord, projectRecord);
194→    expect(edgeCount).toBe(1);
195→  });
196→
197→  it("logs error when feature references nonexistent project (no silent swallow)", async () => {
198→    const tool = makeTool();
199→    const options = makeOptions();
200→
201→    // Create feature referencing a project that doesn't exist — should not throw
202→    const featureResult = await tool.execute!(
203→      { kind: "feature", title: "Ghost Feature", rationale: "No parent", project: "NonexistentProject" },
204→      options,
205→    );
206→
207→    // Feature record is still created successfully
208→    expect(featureResult.kind).toBe("feature");
209→    expect(featureResult.entity_id).toContain("feature:");
210→
211→    // But no has_feature edge (project doesn't exist)
212→    const featureRecord = parseEntityId(featureResult.entity_id);
213→    const [edges] = await surreal
214→      .query<[Array<{ id: RecordId }>]>(
215→        "SELECT id FROM has_feature WHERE out = $feature;",
216→        { feature: featureRecord },
217→      )
218→      .collect<[Array<{ id: RecordId }>]>();
219→    expect(edges).toHaveLength(0);
220→  });
221→
222→  it("race condition: parallel create project + feature fails without sequential dispatch", async () => {
223→    const tool = makeTool();
224→    const options = makeOptions();
225→
226→    // Simulate parallel execution (what happens when LLM batches both calls)
227→    const [projectResult, featureResult] = await Promise.all([
228→      tool.execute!(
229→        { kind: "project", title: "Payments", rationale: "Payment processing" },
230→        options,
231→      ),
232→      tool.execute!(
233→        { kind: "feature", title: "Stripe Integration", rationale: "Accept payments", project: "Payments" },
234→        options,
235→      ),
236→    ]);
237→
238→    expect(projectResult.kind).toBe("project");
239→    expect(featureResult.kind).toBe("feature");
240→
241→    // The feature record exists but the has_feature edge may be missing due to the race.
242→    // This test documents the race condition — the fix is prompt-level sequencing.
243→    const featureRecord = parseEntityId(featureResult.entity_id);
244→    const [edges] = await surreal
245→      .query<[Array<{ id: RecordId }>]>(
246→        "SELECT id FROM has_feature WHERE out = $feature;",
247→        { feature: featureRecord },
248→      )
249→      .collect<[Array<{ id: RecordId }>]>();
250→
